// MARK: - Authentication Service (Server Communication)

protocol AuthenticationServiceProtocol {
    func authenticateWithCredentials(username: String, password: String, completion: @escaping (Result<AuthSession, Error>) -> Void)
    func validateSessionToken(_ token: String, completion: @escaping (Result<AuthSession, Error>) -> Void)
    func refreshSessionToken(_ token: String, completion: @escaping (Result<AuthSession, Error>) -> Void)
}

struct AuthSession {
    let token: String
    let userId: String
    let expiresAt: Date
    
    var isExpired: Bool {
        return Date() >= expiresAt
    }
}

