// MARK: - Authentication Coordinator

class AuthenticationCoordinator {
    
    static let shared = AuthenticationCoordinator()
    
    private let biometricManager = BiometricAuthManager.shared
    private let authService = AuthenticationService.shared
    
    private(set) var currentSession: AuthSession?
    
    var isAuthenticated: Bool {
        guard let session = currentSession else { return false }
        return !session.isExpired
    }
    
    // MARK: - Initial App Launch Authentication
    
    /// Called on app launch to attempt biometric-based session restoration
    func attemptBiometricSessionRestore(completion: @escaping (Result<AuthSession, BiometricAuthManager.AuthError>) -> Void) {
        guard biometricManager.isBiometricAvailable else {
            completion(.failure(.biometricNotAvailable))
            return
        }
        
        guard biometricManager.hasStoredSession else {
            completion(.failure(.noStoredCredential))
            return
        }
        
        let reason = "Authenticate to access your account"
        
        // This triggers REAL biometric auth via the Secure Enclave
        // The token is physically inaccessible without biometric success
        biometricManager.retrieveSessionToken(reason: reason) { [weak self] result in
            switch result {
            case .success(let token):
                // Validate the token with the server
                self?.authService.validateSessionToken(token) { serverResult in
                    switch serverResult {
                    case .success(let session):
                        self?.currentSession = session
                        completion(.success(session))
                    case .failure:
                        // Token is invalid/expired on server side
                        self?.biometricManager.deleteSessionToken()
                        completion(.failure(.sessionExpired))
                    }
                }
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    // MARK: - Password-Based Login with Biometric Enrollment
    
    /// Standard password login, with option to enable biometric for future logins
    func loginWithPassword(username: String, password: String, enableBiometric: Bool, completion: @escaping (Result<AuthSession, BiometricAuthManager.AuthError>) -> Void) {
        authService.authenticateWithCredentials(username: username, password: password) { [weak self] result in
            switch result {
            case .success(let session):
                self?.currentSession = session
                
                if enableBiometric {
                    // Store the session token in biometric-protected keychain
                    self?.biometricManager.storeSessionToken(session.token) { storeResult in
                        switch storeResult {
                        case .success:
                            completion(.success(session))
                        case .failure:
                            // Login succeeded but biometric enrollment failed
                            // Still allow the user in
                            completion(.success(session))
                        }
                    }
                } else {
                    completion(.success(session))
                }
                
            case .failure(let error):
                completion(.failure(.serverAuthFailed(error.localizedDescription)))
            }
        }
    }
    
    // MARK: - Logout
    
    func logout() {
        currentSession = nil
        biometricManager.clearAllSecureData()
    }
    
    func disableBiometric() {
        biometricManager.clearAllSecureData()
    }
}

// MARK: - Login View Controller

class LoginViewController: UIViewController {
    
    private let coordinator = AuthenticationCoordinator.shared
    private let biometricManager = BiometricAuthManager.shared
    
    // UI Elements
    private let containerStackView = UIStackView()
    private let titleLabel = UILabel()
    private let subtitleLabel = UILabel()
    private let usernameTextField = UITextField()
    private let passwordTextField = UITextField()
    private let loginButton = UIButton(type: .system)
    private let biometricButton = UIButton(type: .system)
    private let enableBiometricSwitch = UISwitch()
    private let enableBiometricLabel = UILabel()
    private let activityIndicator = UIActivityIndicatorView(style: .large)
    private let errorLabel = UILabel()
    private let biometricSwitchStack = UIStackView()
    
    private var biometricRetryCount = 0
    private let maxBiometricRetries = 3
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        setupConstraints()
        setupActions()
    }
    
    override func viewDidAppear(_ animated: Bool) {
        super.viewDidAppear(animated)
        
        // Automatically attempt biometric auth if available
        if biometricManager.hasStoredSession && biometricManager.isBiometricAvailable {
            attemptBiometricLogin()
        }
    }
    
    // MARK: - UI Setup
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        
        titleLabel.text = "Welcome Back"
        titleLabel.font = .systemFont(ofSize: 32, weight: .bold)
        titleLabel.textAlignment = .center
        
        subtitleLabel.text = "Sign in to continue"
        subtitleLabel.font = .systemFont(ofSize: 16)
        subtitleLabel.textColor = .secondaryLabel
        subtitleLabel.textAlignment = .center
        
        usernameTextField.placeholder = "Username or Email"
        usernameTextField.borderStyle = .roundedRect
        usernameTextField.autocapitalizationType = .none
        usernameTextField.autocorrectionType = .no
        usernameTextField.textContentType = .username
        usernameTextField.returnKeyType = .next
        
        passwordTextField.placeholder = "Password"
        passwordTextField.borderStyle = .roundedRect
        passwordTextField.isSecureTextEntry = true
        passwordTextField.textContentType = .password
        passwordTextField.returnKeyType = .done
        
        loginButton.setTitle("Sign In", for: .normal)
        loginButton.titleLabel?.font = .systemFont(ofSize: 18, weight: .semibold)
        loginButton.backgroundColor = .systemBlue
        loginButton.setTitleColor(.white, for: .normal)
        loginButton.layer.cornerRadius = 12
        loginButton.heightAnchor.constraint(equalToConstant: 50).isActive = true
        
        let biometricIcon: String
        switch biometricManager.availableBiometricType {
        case .faceID: biometricIcon = "faceid"
        case .touchID: biometricIcon = "touchid"
        case .none: biometricIcon = "lock.shield"
        }
        
        let config = UIImage.SymbolConfiguration(pointSize: 40, weight: .regular)
        biometricButton.setImage(UIImage(systemName: biometricIcon, withConfiguration: config), for: .normal)
        biometricButton.tintColor = .systemBlue
        biometricButton.isHidden = !biometricManager.hasStoredSession || !biometricManager.isBiometricAvailable
        
        enableBiometricLabel.text = "Enable \(biometricManager.biometricDisplayName) for future logins"
        enableBiometricLabel.font = .systemFont(ofSize: 14)
        enableBiometricLabel.textColor = .secondaryLabel
        enableBiometricLabel.numberOfLines = 0
        
        enableBiometricSwitch.isOn = true
        
        biometricSwitchStack.axis = .horizontal
        biometricSwitchStack.spacing = 12
        biometricSwitchStack.alignment = .center
        biometricSwitchStack.addArrangedSubview(enableBiometricSwitch)
        biometricSwitchStack.addArrangedSubview(enableBiometricLabel)
        biometricSwitchStack.isHidden = !biometricManager.isBiometricAvailable
        
        errorLabel.textColor = .systemRed
        errorLabel.font = .systemFont(ofSize: 14)
        errorLabel.textAlignment = .center
        errorLabel.numberOfLines = 0
        errorLabel.isHidden = true
        
        activityIndicator.hidesWhenStopped = true
        
        containerStackView.axis = .vertical
        containerStackView.spacing = 16
        containerStackView.alignment = .fill
        containerStackView.translatesAutoresizingMaskIntoConstraints = false
        
        containerStackView.addArrangedSubview(titleLabel)
        containerStackView.addArrangedSubview(subtitleLabel)
        containerStackView.addArrangedSubview(createSpacer(height: 20))
        containerStackView.addArrangedSubview(biometricButton)
        containerStackView.addArrangedSubview(createSpacer(height: 10))
        containerStackView.addArrangedSubview(usernameTextField)
        containerStackView.addArrangedSubview(passwordTextField)
        containerStackView.addArrangedSubview(biometricSwitchStack)
        containerStackView.addArrangedSubview(errorLabel)
        containerStackView.addArrangedSubview(loginButton)
        containerStackView.addArrangedSubview(activityIndicator)
        
        view.addSubview(containerStackView)
    }
    
    private func setupConstraints() {
        NSLayoutConstraint.activate([
            containerStackView.centerYAnchor.constraint(equalTo: view.centerYAnchor, constant: -40),
            containerStackView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 32),
            containerStackView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -32)
        ])
    }
    
    private func setupActions() {
        loginButton.addTarget(self, action: #selector(loginButtonTapped), for: .touchUpInside)
        biometricButton.addTarget(self, action: #selector(biometricButtonTapped), for: .touchUpInside)
        
        let tapGesture = UITapGestureRecognizer(target: self, action: #selector(dismissKeyboard))
        view.addGestureRecognizer(tapGesture)
    }
    
    private func createSpacer(height: CGFloat) -> UIView {
        let spacer = UIView()
        spacer.heightAnchor.constraint(equalToConstant: height).isActive = true
        return spacer
    }
    
    // MARK: - Actions
    
    @objc private func loginButtonTapped() {
        dismissKeyboard()
        
        guard let username = usernameTextField.text, !username.isEmpty,
              let password = passwordTextField.text, !password.isEmpty else {
            showError("Please enter your username and password.")
            return
        }
        
        setLoading(true)
        hideError()
        
        let enableBiometric = enableBiometricSwitch.isOn && biometricManager.isBiometricAvailable
        
        coordinator.loginWithPassword(
            username: username,
            password: password,
            enableBiometric: enableBiometric
        ) { [weak self] result in
            self?.setLoading(false)
            
            switch result {
            case .success:
                self?.navigateToMainApp()
            case .failure(let error):
                self?.showError(error.localizedDescription)
            }
        }
    }
    
    @objc private func biometricButtonTapped() {
        attemptBiometricLogin()
    }
    
    @objc private func dismissKeyboard() {
        view.endEditing(true)
    }
    
    // MARK: - Biometric Login
    
    private func attemptBiometricLogin() {
        guard biometricRetryCount < maxBiometricRetries else {
            showError("Too many failed attempts. Please sign in with your password.")
            biometricButton.isHidden = true
            return
        }
        
        setLoading(true)
        hideError()
        
        // This triggers REAL biometric authentication via the Secure Enclave.
        // The session token is cryptographically bound to biometric success -
        // it cannot be retrieved without the biometric gate passing.
        coordinator.attemptBiometricSessionRestore { [weak self] result in
            self?.setLoading(false)
            
            switch result {
            case .success:
                self?.navigateToMainApp()
                
            case .failure(let error):
                self?.biometricRetryCount += 1
                
                switch error {
                case .userCancelled:
                    // User chose to use password instead - no error message needed
                    break
                    
                case .biometricFailed:
                    self?.showBiometricRetryAlert()
                    
                case .sessionExpired:
                    self?.showError("Your session has expired. Please sign in with your password.")
                    self?.biometricButton.isHidden = true
                    
                case .noStoredCredential:
                    self?.showError("No saved login found. Please sign in with your password.")
                    self?.biometricButton.isHidden = true
                    
                default:
                    self?.showError(error.localizedDescription)
                }
            }
        }
    }
    
    // MARK: - Alerts
    
    private func showBiometricRetryAlert() {
        let remainingAttempts = maxBiometricRetries - biometricRetryCount
        
        let alert = UIAlertController(
            title: "Authentication Failed",
            message: "\(biometricManager.biometricDisplayName) authentication failed. You have \(remainingAttempts) attempt(s) remaining.",
            preferredStyle: .alert
        )
        
        if remainingAttempts > 0 {
            alert.addAction(UIAlertAction(title: "Try Again", style: .default) { [weak self] _ in
                self?.attemptBiometricLogin()
            })
        }
        
        alert.addAction(UIAlertAction(title: "Use Password", style: .cancel) { [weak self] _ in
            self?.usernameTextField.becomeFirstResponder()
        })
        
        present(alert, animated: true)
    }
    
    // MARK: - UI Helpers
    
    private func setLoading(_ loading: Bool) {
        if loading {
            activityIndicator.startAnimating()
        } else {
            activityIndicator.stopAnimating()
        }
        loginButton.isEnabled = !loading
        biometricButton.isEnabled = !loading
        usernameTextField.isEnabled = !loading
        passwordTextField.isEnabled = !loading
        loginButton.alpha = loading ? 0.6 : 1.0
    }
    
    private func showError(_ message: String) {
        errorLabel.text = message
        errorLabel.isHidden = false
        
        // Shake animation for error feedback
        let animation = CAKeyframeAnimation(keyPath: "transform.translation.x")
        animation.timingFunction = CAMediaTimingFunction(name: .linear)
        animation.duration = 0.4
        animation.values = [-10, 10, -8, 8, -5, 5, 0]
        errorLabel.layer.add(animation, forKey: "shake")
    }
    
    private func hideError() {
        errorLabel.isHidden = true
    }
    
    // MARK: - Navigation
    
    private func navigateToMainApp() {
        let mainVC = MainAppViewController()
        mainVC.modalPresentationStyle = .fullScreen
        mainVC.modalTransitionStyle = .crossDissolve
        present(mainVC, animated: true)
    }
}

