            sessionInfoLabel.text = "Session valid until:\n\(session.expiresAt.formatted())"
        } else {
            sessionInfoLabel.text = "No active session"
        }
        sessionInfoLabel.font = .systemFont(ofSize: 14)
        sessionInfoLabel.textColor = .secondaryLabel
        sessionInfoLabel.textAlignment = .center
        sessionInfoLabel.numberOfLines = 0
        
        let logoutButton = UIButton(type: .system)
        logoutButton.setTitle("Sign Out", for: .normal)
        logoutButton.titleLabel?.font = .systemFont(ofSize: 18, weight: .semibold)
        logoutButton.setTitleColor(.white, for: .normal)
        logoutButton.backgroundColor = .systemRed
        logoutButton.layer.cornerRadius = 12
        logoutButton.addTarget(self, action: #selector(logoutTapped), for: .touchUpInside)
        logoutButton.widthAnchor.constraint(equalToConstant: 200).isActive = true
        logoutButton.heightAnchor.constraint(equalToConstant: 50).isActive = true
        
        let disableBiometricButton = UIButton(type: .system)
        disableBiometricButton.setTitle("Disable Biometric Login", for: .normal)
        disableBiometricButton.titleLabel?.font = .systemFont(ofSize: 14)
        disableBiometricButton.setTitleColor(.systemOrange, for: .normal)
        disableBiometricButton.addTarget(self, action: #selector(disableBiometricTapped), for: .touchUpInside)
        
        stackView.addArrangedSubview(welcomeLabel)
        stackView.addArrangedSubview(sessionInfoLabel)
        stackView.addArrangedSubview(logoutButton)
        stackView.addArrangedSubview(disableBiometricButton)
        
        view.addSubview(stackView)
        
        NSLayoutConstraint.activate([
            stackView.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            stackView.centerYAnchor.constraint(equalTo: view.centerYAnchor)
        ])
    }
    
    @objc private func logoutTapped() {
        let alert = UIAlertController(
            title: "Sign Out",
            message: "Are you sure you want to sign out? You'll need to authenticate again.",
            preferredStyle: .alert
        )
        
        alert.addAction(UIAlertAction(title: "Sign Out", style: .destructive) { [weak self] _ in
            self?.coordinator.logout()
            self?.dismiss(animated: true)
        })
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        
        present(alert, animated: true)
    }
    
    @objc private func disableBiometricTapped() {
        let alert = UIAlertController(
            title: "Disable Biometric Login",
            message: "You'll need to enter your password next time you sign in.",
            preferredStyle: .alert
        )
        
        alert.addAction(UIAlertAction(title: "Disable", style: .destructive) { [weak self] _ in
            self?.coordinator.disableBiometric()
        })
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        
        present(alert, animated: true)
    }
}

// MARK: - App Delegate / Scene Delegate Integration

class AppFlowController {
    
    static let shared = AppFlowController()
    
    private let coordinator = AuthenticationCoordinator.shared
    private let biometricManager = BiometricAuthManager.shared
    
    /// Call this from SceneDelegate's scene(_:willConnectTo:options:)
    func determineInitialViewController() -> UIViewController {
        // Always start with the login screen.
        // The login screen will automatically attempt biometric auth if available.
        // This ensures we never bypass authentication based on a simple flag.
        return LoginViewController()
    }
    
    /// Call this when the app returns to foreground after being backgrounded for a long time
    func handleAppForeground(window: UIWindow?) {
        // If the session is no longer valid, show login
        if !coordinator.isAuthenticated {
            let loginVC = LoginViewController()
            loginVC.modalPresentationStyle = .fullScreen
            window?.rootViewController = loginVC
            window?.makeKeyAndVisible()
        }
    }
}

// MARK: - SceneDelegate Example

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    private var backgroundTimestamp: Date?
    private let sessionTimeoutInterval: TimeInterval = 5 * 60 // 5 minutes
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = (scene as? UIWindowScene) else { return }
        
        let window = UIWindow(windowScene: windowScene)
        window.rootViewController = AppFlowController.shared.determineInitialViewController()
        window.makeKeyAndVisible()
        self.window = window
    }
    
    func sceneDidEnterBackground(_ scene: UIScene) {
        backgroundTimestamp = Date()
    }
    
    func sceneWillEnterForeground(_ scene: UIScene) {
        // If app was backgrounded for too long, require re-authentication
        if let timestamp = backgroundTimestamp,
           Date().timeIntervalSince(timestamp) > sessionTimeoutInterval {
            AppFlowController.shared.handleAppForeground(window: window)
        }
        backgroundTimestamp = nil
    }
}